create extension if not exists pgcrypto;
create table if not exists public.user_device_sessions(id uuid primary key default gen_random_uuid(),user_id uuid not null references public.profiles(id) on delete cascade,device_id text not null check(device_id~'^[A-Za-z0-9_-]{8,128}$'),session_hash text not null,device_label text not null check(char_length(device_label)<=120),platform_label text not null check(char_length(platform_label)<=40),runtime_label text not null check(char_length(runtime_label)<=40),created_at timestamptz not null default now(),last_used_at timestamptz not null default now(),expires_at timestamptz,revoked_at timestamptz,unique(user_id,device_id));
alter table public.user_device_sessions enable row level security;grant select on public.user_device_sessions to authenticated;revoke insert,update,delete on public.user_device_sessions from authenticated;
create policy user_device_sessions_own_select on public.user_device_sessions for select to authenticated using(user_id=auth.uid());
create or replace function public.current_session_hash() returns text language sql stable security definer set search_path=public,pg_temp as $$select encode(extensions.digest(coalesce(auth.jwt()->>'session_id','missing'),'sha256'),'hex')$$;
revoke all on function public.current_session_hash() from public,anon;grant execute on function public.current_session_hash() to authenticated;
create or replace function public.register_current_device_session(target_device_id text,target_device_label text,target_platform_label text,target_runtime_label text) returns uuid language plpgsql security definer set search_path=public,pg_temp as $$declare result_id uuid;begin if auth.uid() is null then raise exception 'AUTH_REQUIRED';end if;if target_device_id!~'^[A-Za-z0-9_-]{8,128}$' then raise exception 'INVALID_DEVICE';end if;insert into public.user_device_sessions(user_id,device_id,session_hash,device_label,platform_label,runtime_label,expires_at)values(auth.uid(),target_device_id,public.current_session_hash(),left(target_device_label,120),left(target_platform_label,40),left(target_runtime_label,40),to_timestamp((auth.jwt()->>'exp')::double precision))on conflict(user_id,device_id)do update set session_hash=excluded.session_hash,device_label=excluded.device_label,platform_label=excluded.platform_label,runtime_label=excluded.runtime_label,last_used_at=now(),expires_at=excluded.expires_at,revoked_at=null returning id into result_id;return result_id;end$$;
create or replace function public.list_current_user_device_sessions() returns table(id uuid,device_label text,platform_label text,runtime_label text,created_at timestamptz,last_used_at timestamptz,expires_at timestamptz,revoked_at timestamptz,current boolean) language sql stable security definer set search_path=public,pg_temp as $$select s.id,s.device_label,s.platform_label,s.runtime_label,s.created_at,s.last_used_at,s.expires_at,s.revoked_at,s.session_hash=public.current_session_hash() from public.user_device_sessions s where s.user_id=auth.uid() order by (s.session_hash=public.current_session_hash()) desc,s.last_used_at desc limit 50$$;
create or replace function public.revoke_other_device_sessions() returns integer language plpgsql security definer set search_path=public,pg_temp as $$declare changed integer;begin update public.user_device_sessions set revoked_at=now() where user_id=auth.uid() and session_hash<>public.current_session_hash() and revoked_at is null;get diagnostics changed=row_count;insert into public.account_security_events(user_id,event_type,metadata)values(auth.uid(),'account_sessions_revoked',jsonb_build_object('scope','others','registered_devices',changed));return changed;end$$;
revoke all on function public.register_current_device_session(text,text,text,text),public.list_current_user_device_sessions(),public.revoke_other_device_sessions() from public,anon;grant execute on function public.register_current_device_session(text,text,text,text),public.list_current_user_device_sessions(),public.revoke_other_device_sessions() to authenticated;
comment on table public.user_device_sessions is 'Safe device metadata only. session_hash is a one-way hash of the JWT session_id; raw access/refresh tokens are never stored.';
